"""The one expensive side effect, behind an interface so it's swappable and fakeable."""
from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass


@dataclass(frozen=True)
class ChargeResult:
    success: bool
    payment_ref: str | None
    error: str | None = None


# ── WHY THIS CLASS ────────────────────────────────────────────────────────────
# PaymentGateway is the Strategy/DI seam: the engine depends on this abstraction,
# never on a concrete vendor. Swapping Stripe for Adyen changes nothing in the engine.
# 🎙️ "I extract the payment behind an interface so the engine doesn't depend on a
#     vendor, and so my tests can inject a fake that fails on purpose."
class PaymentGateway(ABC):
    @abstractmethod
    def charge(self, idempotency_key: str, amount_cents: int) -> ChargeResult: ...


class FakeGateway(PaymentGateway):
    """Always succeeds, and dedups vendor-side on the key (defense in depth)."""
    def __init__(self) -> None:
        self.charge_count = 0
        self._seen: dict[str, ChargeResult] = {}

    def charge(self, idempotency_key: str, amount_cents: int) -> ChargeResult:
        # WHY: even the vendor honours the key — if we somehow call twice with the
        #      same key, the customer is still charged once. Belt and suspenders.
        if idempotency_key in self._seen:
            return self._seen[idempotency_key]
        self.charge_count += 1
        res = ChargeResult(True, f"pay-{idempotency_key}")
        self._seen[idempotency_key] = res
        return res


class ScriptedFakeGateway(PaymentGateway):
    """Returns successes from a list in order: lets me test 'fail then succeed'."""
    def __init__(self, results: list[bool]) -> None:
        self._results = list(results)
        self.charge_count = 0

    def charge(self, idempotency_key: str, amount_cents: int) -> ChargeResult:
        self.charge_count += 1
        ok = self._results.pop(0) if len(self._results) > 1 else self._results[0]
        if ok:
            return ChargeResult(True, f"pay-{idempotency_key}-{self.charge_count}")
        return ChargeResult(False, None, "card_declined")

